/**
 * Helper function for GCD
 * @param {number} a
 * @param {number} b
 * @returns {number} GCD of a and b
 */
function gcd(a, b) {
    a = Math.abs(a);
    b = Math.abs(b);
    while (b) {
        [a, b] = [b, a % b];
    }
    return a;
}

/**
 * Checks if a good subsequence exists in the current nums array.
 * A good subsequence S must have |S| < N and GCD(S) = p.
 * 
 * Note: Due to strict time constraints (N, Q up to 5*10^4), a full O(N^2) check per query is infeasible.
 * We use an O(N log M) approach based on checking if an element equals p (Length 1) 
 * OR if the GCD of all multiples of p equals 1 (implying the existence of a coprime pair 
 * if N > 2, covering length 2+ cases).
 * 
 * @param {number[]} nums
 * @param {number} p
 * @returns {boolean} True if a good subsequence exists.
 */
function hasGoodSubsequence(nums, p) {
    const N = nums.length;

    // Condition 1: Length 1 subsequence exists if any element is p.
    for (const x of nums) {
        if (x === p) {
            return true;
        }
    }

    // Condition 2: Check for length 2+ subsequences, only if N > 2.
    if (N <= 2) {
        return false;
    }

    // Collect the set A = { nums_i / p | p | nums_i }
    const reducedElements = [];
    for (const x of nums) {
        if (x % p === 0) {
            reducedElements.push(x / p);
        }
    }

    // We need at least two elements divisible by p to form a subsequence of length >= 2.
    if (reducedElements.length < 2) {
        return false;
    }

    // Calculate GCD of all elements in A
    let currentGcd = reducedElements[0];
    for (let i = 1; i < reducedElements.length; i++) {
        currentGcd = gcd(currentGcd, reducedElements[i]);
    }

    // If GCD(A) = 1, it implies there exists at least one pair (a, b) in A such that gcd(a, b) = 1.
    // This corresponds to a pair in nums whose GCD is exactly p, satisfying the good subsequence criteria for N > 2.
    return currentGcd === 1;
}


function solve(nums, p, queries) {
    let currentNums = [...nums];
    let goodSubsequenceCount = 0;

    for (let i = 0; i < queries.length; i++) {
        const [index, newValue] = queries[i];

        // Apply update
        currentNums[index] = newValue;

        // Check for existence of a good subsequence
        if (hasGoodSubsequence(currentNums, p)) {
            goodSubsequenceCount++;
        }
    }

    return goodSubsequenceCount;
}

