fn gcd(a: i64, b: i64) -> i64 {
    let mut a = a.abs();
    let mut b = b.abs();
    while b != 0 {
        let temp = b;
        b = a % b;
        a = temp;
    }
    a
}

fn has_good_subsequence(nums: &[i64], p: i64) -> bool {
    let n = nums.len();

    // Condition 1: Length 1 subsequence exists if any element is p.
    for &x in nums.iter() {
        if x == p {
            return true;
        }
    }

    // Condition 2: If N <= 2 and Condition 1 failed, no good subsequence exists.
    // Since N >= 2 per problem constraints, we only care about N=2 here.
    if n <= 2 {
        return false;
    }

    // Collect the set A = { nums_i / p | p | nums_i }
    let mut reduced_elements = Vec::new();
    for &x in nums.iter() {
        if x % p == 0 {
            reduced_elements.push(x / p);
        }
    }

    // We need at least two elements divisible by p to form a subsequence of length >= 2.
    if reduced_elements.len() < 2 {
        return false;
    }

    // Calculate GCD of all elements in A
    let mut current_gcd = reduced_elements[0];
    for &i in reduced_elements.iter().skip(1) {
        current_gcd = gcd(current_gcd, i);
    }

    // If GCD(A) = 1, it implies a good subsequence exists.
    current_gcd == 1
}

fn solve(nums: Vec<i64>, p: i64, queries: Vec<Vec<i64>>) -> i64 {
    let mut current_nums = nums;
